# Step2: Backup Remove Duplicate Association Device
SELECT COUNT(1) 
FROM	CTS_Adhoc.zzzIssueCustMissing_AssociationByDevice_RemoveDup_bk;

INSERT INTO CTS_Adhoc.zzzIssueCustMissing_AssociationByDevice_RemoveDup_bk
SELECT 		Distinct adv.*
FROM		CTS_DataCenter.AssociationByDevice AS	adv
INNER JOIN	CTS_DataCenter.zzzIssueCustMissing_CustDCSAccount AS ms
			ON adv.CTSCustID = ms.CTSCustID
WHERE			ms.NewCTSCustID > 0;
            
#Step 3: Update CreatedDate

UPDATE 		 CTS_DataCenter.AssociationByDevice AS	ads
INNER JOIN  (
SELECT 		ms.NewCTSCustID AS CTSCustID, adv.DCSDeviceID, MIN(adv.CreatedTime) AS CreatedTime
FROM		CTS_Adhoc.zzzIssueCustMissing_AssociationByDevice_RemoveDup_bk AS	adv
INNER JOIN	CTS_DataCenter.zzzIssueCustMissing_CustDCSAccount AS ms
			ON	adv.CTSCustID = ms.CTSCustID
WHERE		ms.NewCTSCustID > 0
GROUP BY 	ms.NewCTSCustID, adv.DCSDeviceID) AS k
			ON ads.CTSCustID = k.CTSCustID
				AND ads.DCSDeviceID = k.DCSDeviceID
SET			ads.CreatedTime = LEAST(k.CreatedTime,ads.CreatedTime);
